export default function QasrApp() {
  const [screen, setScreen] = useState("splash");
  const [historyItem, setHistoryItem] = useState(null);

  return (
    <div style={{ minHeight: "100vh", background: "#DADADA", display: "flex", alignItems: "center", justifyContent: "center", padding: "24px 12px" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans+Arabic:ital,wght@0,400;0,500;0,600;0,700&family=IBM+Plex+Sans:ital,wght@0,400;0,500;0,600;0,700&display=swap');
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.45; } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes pop { 0% { transform: scale(0.6); opacity: 0; } 70% { transform: scale(1.08); opacity: 1; } 100% { transform: scale(1); } }
        @keyframes slideDownHeading { from { top: 91px; } to { top: 141px; } }
        @keyframes slideUpIn { from { opacity: 0; transform: translateY(28px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes slideInRight { from { opacity: 0; transform: translateX(50px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes dissolveIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
      <div dir="rtl" style={{ width: W, height: H, position: "relative", borderRadius: 28, overflow: "hidden", boxShadow: "0 30px 70px rgba(0,0,0,0.35)", fontFamily: FONT }}>
        {screen === "splash" && <Splash onEnter={() => setScreen("home")} />}
        {screen === "home" && (
          <Home
            onVerifyBank={() => setScreen("verifyBank")}
            onVerifyInstitution={() => setScreen("verifyInstitution")}
            onHistory={() => setScreen("history")}
            onLink={() => setScreen("privacy")}
            onReport={() => setScreen("report")}
          />
        )}
        {screen === "verifyInstitution" && <VerifyInstitution onBack={() => setScreen("home")} />}
        {screen === "verifyBank" && <VerifyBank onBack={() => setScreen("home")} />}
        {screen === "report" && <ReportFraud onBack={() => setScreen("home")} />}
        {screen === "history" && (
          <History onBack={() => setScreen("home")} onOpenItem={(item) => { setHistoryItem(item); setScreen("historyDetail"); }} />
        )}
        {screen === "historyDetail" && <HistoryDetail item={historyItem} onBack={() => setScreen("history")} />}
        {screen === "privacy" && <PrivacyConsent onBack={() => setScreen("home")} onAgree={() => setScreen("linkAccount")} />}
        {screen === "linkAccount" && <LinkAccount onBack={() => setScreen("privacy")} onDone={() => setScreen("home")} />}
      </div>
    </div>
  );
}

