/* ================= Verify Bank / Transaction check ================= */
function VerifyBank({ onBack }) {
  const [customerId, setCustomerId] = useState("");
  const [isIntl, setIsIntl] = useState(false);
  const [amount, setAmount] = useState("");
  const [category, setCategory] = useState("grocery");
  const [payment, setPayment] = useState("card");
  const [status, setStatus] = useState("idle");
  const [result, setResult] = useState(null);
  const tint = "rgba(20.33, 104.75, 183.89, 0.1)";

  async function handleSubmit() {
    if (!customerId.trim() || !amount || Number(amount) <= 0) return;
    setStatus("loading");
    const payload = {
      customer_id: customerId.trim(),
      is_international: isIntl,
      transaction_amount: Number(amount),
      merchant_category: category,
      payment_method: payment,
    };
    try {
      const res = await fetch(API_URL, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(payload) });
      if (!res.ok) throw new Error();
      setResult(await res.json());
      setStatus("done");
    } catch {
      setStatus("error");
    }
  }

  if (status === "done" && result) {
    return <ResultScreen result={result} name={`${customerId} — ${amount} ر.س`} accent={NAVY} onBack={onBack} onRetry={() => setStatus("idle")} />;
  }

  const canSubmit = customerId.trim() && amount;

  return (
    <div style={{ width: "100%", height: "100%", position: "relative", overflow: "hidden", background: "linear-gradient(179.17deg, #76afe5, #032341)" }}>
      <BlobBg tone="blue" />
      <div style={{ position: "absolute", top: 246, left: 1, width: 402, height: 716, borderRadius: 71, background: "white", boxShadow: "0px 4px 4px rgba(0,0,0,0.25)" }} />
      {status === "loading" && <LoadingOverlay text="جارِ التحقق من المعاملة..." />}

      <div style={{ position: "absolute", top: 46, left: 29, width: 41, height: 41, animation: "fadeUp 0.4s ease both" }}><BackIconBlue onClick={onBack} /></div>

      <div style={{ position: "absolute", top: 111, left: 130, width: 237, fontSize: 40, fontWeight: 700, color: NAVY, background: `linear-gradient(90deg, ${NAVY}, ${NAVY2})`, backgroundClip: "text", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", textAlign: "right", lineHeight: 1.2, animation: "fadeUp 0.4s ease 0.05s both" }}>
        تحقق من حساب بنكي
      </div>

      <div style={{ position: "absolute", top: 300, left: 42, width: 333, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right" }}>رقم العميل / الآيبان</div>
      <TintField top={333} left={42} width={333} height={39} tint={tint} value={customerId} onChange={setCustomerId} />

      <div style={{ position: "absolute", top: 385, left: 42, width: 333, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right" }}>مبلغ الحوالة</div>
      <TintField top={418} left={42} width={333} height={39} tint={tint} value={amount} onChange={setAmount} />

      <div style={{ position: "absolute", top: 470, left: 41, width: 333, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right" }}>الفئة</div>
      <TintField top={499} left={41} width={333} height={39} tint={tint} value={category} onChange={setCategory} select
        options={[["grocery", "بقالة"], ["electronics", "إلكترونيات"], ["travel", "سفر"], ["fuel", "وقود"], ["restaurant", "مطاعم"]]} />

      <div style={{ position: "absolute", top: 551, left: 41, width: 333, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right" }}>طريقة الدفع</div>
      <TintField top={580} left={41} width={333} height={39} tint={tint} value={payment} onChange={setPayment} select
        options={[["card", "بطاقة"], ["transfer", "تحويل"], ["wallet", "محفظة إلكترونية"]]} />

      <label style={{ position: "absolute", top: 635, left: 42, display: "flex", alignItems: "center", gap: 8, fontSize: 15, fontWeight: 700, color: NAVY, cursor: "pointer" }}>
        <input type="checkbox" checked={isIntl} onChange={(e) => setIsIntl(e.target.checked)} style={{ width: 18, height: 18 }} />
        معاملة دولية؟
      </label>

      {status === "error" && <p style={{ position: "absolute", top: 675, left: 42, width: 333, color: "#9D0303", fontSize: 11, textAlign: "right" }}>تعذر الاتصال بالسيرفر (localhost:5000)</p>}

      <button onClick={handleSubmit} disabled={!canSubmit} style={{ position: "absolute", top: 724, left: "calc(50% - 114px)", width: 227, height: 50, border: "none", background: "none", cursor: canSubmit ? "pointer" : "default", padding: 0, opacity: canSubmit ? 1 : 0.5 }}>
        <div style={{ position: "absolute", top: 2, left: 0, width: 227, height: 45 }}><NavyButtonBg /></div>
        <span style={{ position: "relative", color: "white", fontSize: 24, fontWeight: 700 }}>تحقق</span>
      </button>
    </div>
  );
}

/* ================= Result screen (shared) ================= */
const TIER_STYLES = {
  safe: { color: "#769F43", bg: "#F0F7E8" },
  mid_safe: { color: "#C88902", bg: "#FDF4E3" },
  fraud_danger: { color: "#9D0303", bg: "#FBE4E2" },
};

function ResultScreen({ result, name, accent, onBack, onRetry }) {
  const style = TIER_STYLES[result.tier] || TIER_STYLES.safe;
  return (
    <div style={{ width: "100%", height: "100%", position: "relative", background: "#F4FAFF", overflow: "hidden" }}>
      <div style={{ padding: "70px 27px 30px", animation: "fadeUp 0.35s ease" }}>
        <button onClick={onBack} style={{ background: "none", border: "none", cursor: "pointer", color: accent, fontSize: 22, fontWeight: 700, marginBottom: 18 }}>→</button>

        <div style={{ textAlign: "center", marginBottom: 22 }}>
          <div style={{ width: 100, height: 100, borderRadius: "50%", margin: "0 auto 16px", background: `conic-gradient(${style.color} ${result.risk_score * 3.6}deg, #E7ECF5 0deg)`, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div style={{ width: 80, height: 80, borderRadius: "50%", background: "#F4FAFF", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
              <span style={{ fontSize: 22, fontWeight: 700, color: style.color }}>{result.risk_score}</span>
              <span style={{ fontSize: 9, color: "#5B6B8C" }}>من 100</span>
            </div>
          </div>
          <div style={{ fontSize: 22, fontWeight: 700, color: style.color }}>{result.tier_label_ar}</div>
          <div style={{ fontSize: 12.5, color: "#5B6B8C", marginTop: 4 }}>{name}</div>
        </div>

        {result.explanation && (
          <div style={{ background: "white", borderRadius: 16, padding: 18, marginBottom: 16 }}>
            <p style={{ fontSize: 13, color: NAVY, lineHeight: 1.8, margin: 0, textAlign: "right" }}>{result.explanation}</p>
          </div>
        )}

        {result.top_factors && (
          <div style={{ marginBottom: 22 }}>
            <div style={{ fontSize: 12, color: "#5B6B8C", fontWeight: 700, marginBottom: 10, textAlign: "right" }}>أهم العوامل المؤثرة</div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6, justifyContent: "flex-start" }}>
              {result.top_factors.slice(0, 4).map((f, i) => (
                <span key={i} style={{ fontSize: 11, background: "white", color: NAVY, padding: "6px 12px", borderRadius: 999, borderRight: `3px solid ${style.color}` }}>{f}</span>
              ))}
            </div>
          </div>
        )}

        <button onClick={onRetry} style={{ width: 141, height: 45, display: "block", margin: "0 auto", background: accent, borderRadius: 11, border: "none", color: "white", fontSize: 16, fontWeight: 700, cursor: "pointer" }}>تحقق جديد</button>
      </div>
    </div>
  );
}

/* ================= Report Fraud (frontend-only) ================= */
function ReportFraud({ onBack }) {
  const [username, setUsername] = useState("");
  const [platform, setPlatform] = useState("");
  const [file, setFile] = useState(null);
  const [status, setStatus] = useState("idle"); // idle | loading | done
  const [reportCount, setReportCount] = useState(1284);

  function handleSubmit() {
    if (!username.trim() || !file) return;
    setStatus("loading");
    setTimeout(() => {
      setReportCount((c) => c + 1);
      setStatus("done");
    }, 1200);
  }

  if (status === "done") {
    return (
      <div style={{ width: "100%", height: "100%", position: "relative", background: NAVY, overflow: "hidden" }}>
        <SuccessOverlay
          title="تم إرسال البلاغ"
          subtitle={`بفضل تعاونكم، تم كشف ${reportCount} حالة احتيال حتى الآن.`}
          onDone={onBack}
        />
      </div>
    );
  }

  const tint = "rgba(157, 199, 255, 0.15)";
  const canSubmit = username.trim() && file;

  return (
    <div style={{ width: "100%", height: "100%", position: "relative", background: NAVY, overflow: "hidden" }}>
      {status === "loading" && <LoadingOverlay text="جارِ إرسال البلاغ..." />}
      <div style={{ padding: "70px 27px 30px" }}>
        <button onClick={onBack} style={{ background: "rgba(255,255,255,0.12)", border: "none", borderRadius: "50%", width: 41, height: 41, color: "white", fontSize: 20, cursor: "pointer", marginBottom: 24 }}>→</button>

        <h1 style={{ color: "#F4FAFF", fontSize: 28, fontWeight: 700, margin: "0 0 8px", textAlign: "right" }}>أبلغ عن احتيال</h1>
        <p style={{ color: "#8FA0BE", fontSize: 13, margin: "0 0 30px", textAlign: "right", lineHeight: 1.7 }}>
          بلاغك يساعدنا نحمي مستخدمين ثانيين من نفس عملية الاحتيال
        </p>

        <div style={{ marginBottom: 20 }}>
          <label style={{ display: "block", textAlign: "right", color: "white", fontSize: 14.5, fontWeight: 700, marginBottom: 8 }}>اسم المستخدم / الحساب المُبلَّغ عنه</label>
          <input
            dir="rtl"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            placeholder="مثال: @user1234"
            style={{ width: "100%", boxSizing: "border-box", height: 46, background: tint, border: "none", borderRadius: 12, padding: "0 14px", fontSize: 14, color: "white", outline: "none", fontFamily: FONT, textAlign: "right" }}
          />
        </div>

        <div style={{ marginBottom: 20 }}>
          <label style={{ display: "block", textAlign: "right", color: "white", fontSize: 14.5, fontWeight: 700, marginBottom: 8 }}>المنصة اللي صار فيها الاحتيال</label>
          <select
            dir="rtl"
            value={platform}
            onChange={(e) => setPlatform(e.target.value)}
            style={{ width: "100%", boxSizing: "border-box", height: 46, background: tint, border: "none", borderRadius: 12, padding: "0 14px", fontSize: 14, color: "white", outline: "none", fontFamily: FONT, textAlign: "right" }}
          >
            <option value="" style={{ color: "black" }}>اختاري المنصة</option>
            <option value="whatsapp" style={{ color: "black" }}>واتساب</option>
            <option value="sms" style={{ color: "black" }}>رسالة نصية (SMS)</option>
            <option value="instagram" style={{ color: "black" }}>انستقرام</option>
            <option value="x" style={{ color: "black" }}>X (تويتر)</option>
            <option value="call" style={{ color: "black" }}>مكالمة هاتفية</option>
            <option value="other" style={{ color: "black" }}>أخرى</option>
          </select>
        </div>

        <div style={{ marginBottom: 30 }}>
          <label style={{ display: "block", textAlign: "right", color: "white", fontSize: 14.5, fontWeight: 700, marginBottom: 8 }}>لقطة شاشة للرسالة</label>
          <label
            style={{
              display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 8,
              width: "100%", boxSizing: "border-box", minHeight: 110, background: tint, borderRadius: 12,
              border: "1.5px dashed rgba(255,255,255,0.35)", cursor: "pointer", padding: 14,
            }}
          >
            <input type="file" accept="image/*" onChange={(e) => setFile(e.target.files?.[0] || null)} style={{ display: "none" }} />
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M12 16V4M12 4l-4 4M12 4l4 4M4 16v2a2 2 0 002 2h12a2 2 0 002-2v-2" stroke="#9DC7FF" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" /></svg>
            <span style={{ color: file ? "white" : "#9DC7FF", fontSize: 12.5, textAlign: "center" }}>
              {file ? file.name : "اضغطي لرفع لقطة الشاشة"}
            </span>
          </label>
        </div>

        <button
          onClick={handleSubmit}
          disabled={!canSubmit}
          style={{
            width: "100%", padding: "14px 0", borderRadius: 12, border: "none",
            background: canSubmit ? "#9D0303" : "rgba(157,3,3,0.4)", color: "white",
            fontSize: 16, fontWeight: 700, cursor: canSubmit ? "pointer" : "default",
          }}
        >
          إرسال البلاغ
        </button>
      </div>
    </div>
  );
}


