/* ================= Privacy Consent ================= */
function PrivacyConsent({ onBack, onAgree }) {
  return (
    <div style={{ width: "100%", height: "100%", position: "relative", background: "linear-gradient(-13.05deg, #C36B4E, #AE6046 50%, #5D3325)", overflow: "hidden", textAlign: "center", fontFamily: FONT }}>
      <button onClick={onBack} style={{ position: "absolute", top: 20, left: 20, background: "rgba(255,255,255,0.15)", border: "none", borderRadius: "50%", width: 36, height: 36, color: "white", fontSize: 18, cursor: "pointer" }}>→</button>

      <div style={{ position: "absolute", top: "calc(50% - 105px)", left: "calc(50% - 128px)", width: 256, height: 43, animation: "slideInRight 0.5s ease both" }}>
        <div style={{ position: "absolute", top: "calc(50% - 21.5px)", left: "calc(50% - 116.65px)", borderRadius: 15, background: "#F4FAFF", width: 233.3, height: 43 }} />
        <div style={{ position: "absolute", top: 4.78, left: 0, width: 256, height: 29.6, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, fontWeight: 600, color: TERRA }}>
          نحرص على خصوصيتك
        </div>
      </div>

      <p style={{ position: "absolute", top: 392, left: 49, width: 304, fontWeight: 600, fontFamily: FONT, fontSize: 14, color: "#F4FAFF", lineHeight: 1.8, margin: 0, animation: "slideInRight 0.5s ease 0.12s both" }}>
        يقوم قصر بتتبع حوالاتك المالية ومشترياتك من المتاجر الالكترونية بغرض التحقق منها، كما تستخدم هذه البيانات لغرض البحث وتدريب النماذج.
      </p>
      <p style={{ position: "absolute", top: 474, left: 49, width: 304, fontWeight: 600, fontFamily: FONT, fontSize: 14, color: "#F4FAFF", margin: 0, animation: "slideInRight 0.5s ease 0.22s both" }}>
        كما يمكنك الغاء هذه الخاصية في أي وقت
      </p>

      <button onClick={onAgree} style={{ position: "absolute", top: 495, left: 130, width: 142, height: 67, background: "none", border: "none", cursor: "pointer", animation: "slideInRight 0.5s ease 0.32s both" }}>
        <div style={{ position: "absolute", top: 20, left: 20, width: 102, height: 27 }}><OutlinePillBg /></div>
        <span style={{ position: "absolute", top: 24, left: 24, width: 94, height: 19, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 600, fontSize: 14, color: "white" }}>أبدأ الربط</span>
      </button>
    </div>
  );
}

/* ================= Link Account ================= */
function LinkAccount({ onBack, onDone }) {
  const [name, setName] = useState("");
  const [bank, setBank] = useState("");
  const [account, setAccount] = useState("");
  const [status, setStatus] = useState("idle");
  const gradTint = "linear-gradient(90deg, rgba(8,90,167,0.15), rgba(8,90,167,0.5))";

  function handleSubmit() {
    if (!name.trim() || !bank.trim() || !account.trim()) return;
    setStatus("loading");
    setTimeout(() => setStatus("success"), 1400);
  }

  if (status === "success") {
    return (
      <div style={{ width: "100%", height: "100%", position: "relative", background: "#b7d8f7" }}>
        <SuccessOverlay title="تم الربط بنجاح" subtitle="راح نراقب حسابك البنكي وننبهك فورًا لو صار أي نشاط مشبوه." onDone={onDone} />
      </div>
    );
  }

  return (
    <div style={{ width: "100%", height: "100%", position: "relative", background: "#B7D8F7", overflow: "hidden", textAlign: "right", fontFamily: FONT }}>
      <div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg, rgba(184,217,248,0), #085AA7)" }} />
      {status === "loading" && <LoadingOverlay text="جارِ ربط الحساب..." />}

      <button onClick={onBack} style={{ position: "absolute", top: 20, left: 20, background: "rgba(255,255,255,0.4)", border: "none", borderRadius: "50%", width: 36, height: 36, color: NAVY, fontSize: 18, cursor: "pointer", zIndex: 2 }}>→</button>

      <div style={{ position: "absolute", top: 266, left: 24, width: 354, height: 512, borderRadius: 49, background: "#B7D8F7", boxShadow: "0px 4px 4px rgba(0,0,0,0.25)", animation: "slideUpIn 0.5s ease both" }} />

      <div style={{ position: "absolute", top: 153, left: "calc(50% - 130px)", width: 259, fontSize: 34, fontWeight: 700, textAlign: "center", color: NAVY, background: `linear-gradient(90deg, ${NAVY}, #1469B8)`, backgroundClip: "text", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", animation: "slideUpIn 0.5s ease 0.05s both" }}>
        أربط حسابك البنكي مع قصر
      </div>

      <div style={{ position: "absolute", top: 327, left: 43, width: 320, fontSize: 15, fontWeight: 700, color: NAVY, textAlign: "right", lineHeight: 1.4, animation: "slideUpIn 0.5s ease 0.15s both" }}>اسمك كما هو مسجل في الهوية الوطنية/ الإقامة</div>
      <input dir="rtl" value={name} onChange={(e) => setName(e.target.value)} style={{ position: "absolute", top: 396, left: 43, width: 320, height: 43, boxSizing: "border-box", background: gradTint, border: "none", borderRadius: 12, padding: "0 14px", fontSize: 14, fontWeight: 500, color: NAVY, outline: "none", fontFamily: FONT, textAlign: "right", animation: "slideUpIn 0.5s ease 0.2s both" }} />

      <div style={{ position: "absolute", top: 445, left: 43, width: 320, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right", animation: "slideUpIn 0.5s ease 0.25s both" }}>البنك</div>
      <select dir="rtl" value={bank} onChange={(e) => setBank(e.target.value)} style={{ position: "absolute", top: 491, left: 43, width: 320, height: 43, boxSizing: "border-box", background: gradTint, border: "none", borderRadius: 12, padding: "0 14px", fontSize: 14, fontWeight: 500, color: NAVY, outline: "none", fontFamily: FONT, textAlign: "right", animation: "slideUpIn 0.5s ease 0.3s both" }}>
        <option value="">اختار البنك</option>
        <option value="rajhi">الراجحي</option>
        <option value="ncb">الأهلي</option>
        <option value="riyad">بنك الرياض</option>
      </select>

      <div style={{ position: "absolute", top: 540, left: 30, width: 333, fontSize: 16, fontWeight: 700, color: NAVY, textAlign: "right", animation: "slideUpIn 0.5s ease 0.35s both" }}>رقم الحساب البنكي</div>
      <input dir="rtl" value={account} onChange={(e) => setAccount(e.target.value)} style={{ position: "absolute", top: 588, left: 43, width: 320, height: 43, boxSizing: "border-box", background: gradTint, border: "none", borderRadius: 12, padding: "0 14px", fontSize: 14, fontWeight: 500, color: NAVY, outline: "none", fontFamily: FONT, textAlign: "right", animation: "slideUpIn 0.5s ease 0.4s both" }} />

      <button onClick={handleSubmit} disabled={!name.trim() || !bank.trim() || !account.trim()} style={{ position: "absolute", top: 679, left: "calc(50% - 110px)", width: 227, height: 50, border: "none", background: "none", cursor: "pointer", padding: 0, opacity: name.trim() && bank.trim() && account.trim() ? 1 : 0.5, animation: "slideUpIn 0.5s ease 0.45s both" }}>
        <div style={{ position: "absolute", top: 2, left: 0, width: 227, height: 45 }}><NavyButtonBg /></div>
        <span style={{ position: "relative", color: "white", fontSize: 24, fontWeight: 700 }}>ربط</span>
      </button>
    </div>
  );
}
